INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('52e2987a-86c8-5c60-8de5-0aa32684f24e', '9b7c239c-5ad4-4879-8fcd-c76371a51a6f', 'He was born in New York, so he is an ___.', '他出生在紐約，所以他是一個美國人。', 'American', 'engineer', 'officer', 'artist', 'America (美國) + -n (指代人) → 美國人。', 'America (美國) + n (人) → 美國人。', '2026-07-06 14:02:33', '2026-07-06 14:02:33'),
('463ec6fe-f721-5ab6-8e33-cbe3b8592332', 'cd1cf942-d9a2-4e92-a612-18edc4edb1e5', 'The new software allows employees to ___ sensitive data more efficiently.', '這款新軟體讓員工能更有效率地存取敏感資料。', 'access', 'avoid', 'create', 'delete', 'access 由前綴 ac- (朝向) 與詞根 cess (走) 組成 → 朝向某處走去 → 接近、使用或存取。', 'ac (朝向) + ess (走) → 走過去 → 接近、存取。', '2026-07-06 16:43:10', '2026-07-06 16:43:10'),
('eee8e248-93eb-5d4c-9c9d-d700d6def716', '1ea11d1b-2b90-43da-b381-17b2fe2a7c73', 'The detective''s report lacked ___ , making it difficult for the jury to reach a verdict.', '偵探的報告缺乏準確性，使得陪審團難以做出判決。', 'accuracy', 'efficiency', 'intensity', 'stability', '由形容詞 accurate (準確的) 加上名詞字尾 -acy 轉化而來，表示一種狀態或性質。', 'accurate (準確的) + acy (名詞字尾) → accuracy (準確性)。想像射箭時，箭射中靶心的精準度就是 accuracy。', '2026-07-06 17:00:46', '2026-07-06 17:00:46'),
('6dc52b0e-3e3a-5292-a7a4-8662a98af4de', 'ebf2038b-71f7-4ae7-9516-f180fb4735d1', 'My grandfather is very ___; he goes hiking every morning.', '我祖父非常活躍；他每天早上都去健行。', 'active', 'quiet', 'careful', 'brave', 'act (做/行動) + ive (形容詞字尾) → 活躍的、主動的。', '記住 act 是「行動」，加上 ive 字尾就變成形容詞「活躍的」。', '2026-07-06 13:06:23', '2026-07-06 13:06:23'),
('0892fcbd-8c12-58db-8a43-a09001e826ca', '0091fdd7-5831-4c40-991a-f7f99e369ce3', 'The sudden loud ___ made everyone run out of the building.', '突如其來的巨大聲響讓每個人都逃出了建築物。', 'alarm', 'music', 'dream', 'story', 'al- (向/往) + arm (武裝/裝備) → 原意為「呼籲作戰」，引申為「警報」或「使驚慌不安」。', '想像在戰場上大聲呼喊「Arm! Arm! (武裝起來！)」來提醒大家，就是 alarm (警報)。', '2026-07-05 05:54:57', '2026-07-05 05:54:57'),
('3d3ba188-f155-5097-a16b-0d0e0af77e46', '2bcb0ca4-f12e-4a0b-a5a2-6dc50a3f705d', 'The conservation program aims to protect every endangered ___ in this region.', '這項保育計畫旨在保護該地區的每一種瀕危動物。', 'animal', 'building', 'vehicle', 'instrument', 'anim (生命/靈魂)', 'animal (動物) → 來自拉丁語 anima (生命/靈魂)', '2026-07-06 21:21:36', '2026-07-06 21:21:36'),
('8887b482-b13a-5e44-a481-71e26bb16f7a', 'b83b8208-2682-4530-99f1-ce0dded5419e', 'The professional ___ used a powerful telescope to observe the mysterious phenomena in deep space.', '這位專業的天文學家使用強大的望遠鏡來觀察深空中的神秘現象。', 'astronomer', 'architect', 'physician', 'athlete', '前綴 astro- 表示「星星」或「天體」。', 'astro (星星) + nomer (命名/規則) → 研究星星規律的人就是天文學家。', '2026-07-07 01:41:24', '2026-07-07 01:41:24'),
('835f45cd-882b-55ea-aa3c-0d88d0b90b2e', '8310892e-d212-4818-9b3f-478655bd3d24', 'The man has a long, black ___ on his face.', '這個男人的臉上有長長的黑鬍子。', 'beard', 'hat', 'ring', 'bag', 'beard 為單字本身，指長在臉上的鬍子。', '記法：beard 讀音與 bear (熊) 相近，想像熊臉上的毛跟鬍子很像。', '2026-07-07 02:46:24', '2026-07-07 02:46:24'),
('b6b6fa95-4c2d-5707-b892-7ce783f94b9a', '1aef6e88-c1f9-4d54-90b2-60bd15b68c08', 'Look! A colorful ___ is flying near the flower.', '看！一隻色彩繽紛的蝴蝶正在花朵附近飛舞。', 'butterfly', 'bird', 'bee', 'spider', '由 butter (奶油) → fly (飛) 組成', '想像一隻色彩像奶油一樣鮮豔、在空中飛舞的小生物。', '2026-07-07 09:07:29', '2026-07-07 09:07:29'),
('f7701a93-7d6e-5834-9a0e-0fece0c2c966', '9b1f7075-5747-4be4-adf1-70c8a7d6a0ac', 'He ___ play the piano very well despite his age.', '儘管年紀大了，他仍能流利地彈奏鋼琴。', 'can', 'must', 'will', 'should', 'can 作為助動詞，表示「能夠」或「會」。', 'Can ＝ 能夠 (能力)', '2026-07-05 12:16:09', '2026-07-05 12:16:09'),
('3fdd8cef-87dc-54b6-bc34-a55fccb63b3a', '6af03300-b5b5-4c65-97e5-2cce67e5a162', 'The rabbit is eating a long, orange ___.', '那隻兔子正在吃一根長長的、橘色的胡蘿蔔。', 'carrot', 'potato', 'apple', 'bread', 'carrot 為名詞，指胡蘿蔔。', '記住兔子(rabbit)最喜歡吃橘色的 carrot。', '2026-07-07 02:34:24', '2026-07-07 02:34:24'),
('e75929bb-f011-5c32-a9a0-7c377e1a8c1e', '2da7118a-92c9-4498-b696-4f486c445a09', 'Many people ___ him because he is very famous and rich.', '很多人很羨慕他，因為他非常有名且富有。', 'envy', 'hate', 'help', 'call', 'envy 為動詞，表示羨慕或嫉妒。', '看到別人的好東西，心裡發出「恩...非」的感嘆，覺得好酸喔！(羨慕/嫉妒)', '2026-07-07 04:13:27', '2026-07-07 04:13:27'),
('494669be-b850-5bed-8a70-36f180aafefa', '8a429cfc-293b-4036-9258-d3449418b320', 'Don''t worry, ___ will be fine.', '別擔心，一切都會好起來的。', 'everything', 'someone', 'something', 'anything', 'every (每一) + thing (事物)', 'every (每一) + thing (事物) → everything (每樣事物)', '2026-07-07 04:53:27', '2026-07-07 04:53:27'),
('332dcd08-4b53-5486-a368-6b70a595e206', 'a04dcb81-183a-42ed-8bfa-c35eb8de075b', 'It is too hot in the classroom, so let''s turn on the ___.', '教室裡太熱了，所以我們把電風扇打開吧。', 'fan', 'clock', 'lamp', 'radio', 'fan 作為名詞時，也可以表示「電風扇」。', '天氣熱的時候，我們需要用 fan (電風扇) 來吹涼。', '2026-07-07 04:52:34', '2026-07-07 04:52:34'),
('c8eb2cc0-cd2f-59ac-aefd-02631aa2e5ee', 'a2d89bc0-aa6e-42b6-bf38-ebfa28cb35d1', 'Is ___ any milk in the fridge?', '冰箱裡有牛奶嗎？', 'there', 'this', 'that', 'it', 'Is there...? 用於詢問「某處是否有...」。', 'Is there...? → 有...嗎？', '2026-07-06 10:42:39', '2026-07-06 10:42:39');
